import { query } from '@anthropic-ai/claude-agent-sdk';

const conversation = query({
  prompt: 'Analise src/auth.ts e liste os problemas de segurança',
  options: {
    model: 'sonnet',
    maxTurns: 5,
    permissionMode: 'plan'
  }
});

for await (const message of conversation) {
  console.log(message.type, message.content);
}

const conversation = query({
  prompt: 'Crie um componente de login',
  options: {
    settingSources: ['user', 'project'],  // carrega CLAUDE.md e skills
    permissionMode: 'acceptEdits',
    allowedTools: ['Read', 'Edit', 'Bash(npm:*)']  // pré-aprova ferramentas
  }
});
